export function getRelatedContentPages(currentSlug: string, currentCluster: PtaContentCluster): PtaContentPage[] {
  return PTA_SEO_CONTENT_PAGES.filter(
    (page) => page.slug !== currentSlug && page.relatedLinks.some((link) => link.slug === currentSlug)
  ).slice(0, 4);
}

export function getClusterPages(cluster: PtaContentCluster): PtaContentPage[] {
  return PTA_SEO_CONTENT_PAGES.filter((page) => page.cluster === cluster);
}

export function getAllPtaSeoSlugs(): string[] {
  return [
    ...PTA_SEO_CONTENT_PAGES.map((p) => p.slug),
    ...PTA_BLOG_PAGES.map((p) => p.slug),
  ];
}

